        "vmin.s32.s32.s32 %3, %3, %8, %3;\n\t"
        "vmin.s32.s32.s32 %4, %4, %8, %4;\n\t"
        "vmin.s32.s32.s32 %5, %5, %8, %5;\n\t"
        "vmin.s32.s32.s32 %6, %6, %8, %6;\n\t"
        "vmin.s32.s32.s32 %7, %7, %8, %7;\n\t"
        :"+r"(r0),"+r"(r1),"+r"(r2),"+r"(r3),"+r"(r4),"+r"(r5),"+r"(r6),"+r"(r7):"r"(k0));
    out[threadIdx.y*32+threadIdx.x] = r0;
}

