// ============================================================================
// Runner
// ============================================================================

struct Test {
    const char* name;
    void* tput;
    void* lat;
    int min_sm;
    char out_type;   // 'f'=float, 'i'=int, 'u'=unsigned, 's'=unsigned short, 'd'=double
};

template<typename T>
float bench_kernel(void* fn_ptr, T* d_out, int n_iters, int n_warmup, int n_reps) {
    typedef void (*KFn)(volatile T*, int);
    KFn fn = (KFn)fn_ptr;
    dim3 block(32, 4);
    for (int w = 0; w < n_warmup; w++) fn<<<1, block>>>(d_out, n_iters);
    CHECK(cudaDeviceSynchronize());

    cudaEvent_t t0, t1;
    CHECK(cudaEventCreate(&t0));
    CHECK(cudaEventCreate(&t1));

    float total_ms = 0;
    for (int r = 0; r < n_reps; r++) {
        CHECK(cudaEventRecord(t0));
        fn<<<1, block>>>(d_out, n_iters);
        CHECK(cudaEventRecord(t1));
        CHECK(cudaEventSynchronize(t1));
        float ms;
        CHECK(cudaEventElapsedTime(&ms, t0, t1));
        total_ms += ms;
    }
    CHECK(cudaEventDestroy(t0));
    CHECK(cudaEventDestroy(t1));
    return total_ms / n_reps;
}

Test tests[] = {
    {"f64_add", (void*)kern_f64_add_tput, (void*)kern_f64_add_lat, 75, 'd'},
    {"f64_sub", (void*)kern_f64_sub_tput, (void*)kern_f64_sub_lat, 75, 'd'},
    {"f64_mul", (void*)kern_f64_mul_tput, (void*)kern_f64_mul_lat, 75, 'd'},
    {"f64_fma", (void*)kern_f64_fma_tput, (void*)kern_f64_fma_lat, 75, 'd'},
    {"f64_min", (void*)kern_f64_min_tput, (void*)kern_f64_min_lat, 75, 'd'},
    {"f64_max", (void*)kern_f64_max_tput, (void*)kern_f64_max_lat, 75, 'd'},
    {"f64_div_rn", (void*)kern_f64_div_rn_tput, (void*)kern_f64_div_rn_lat, 75, 'd'},
    {"f64_rcp_rn", (void*)kern_f64_rcp_rn_tput, (void*)kern_f64_rcp_rn_lat, 75, 'd'},
    {"f64_sqrt_rn", (void*)kern_f64_sqrt_rn_tput, (void*)kern_f64_sqrt_rn_lat, 75, 'd'},
    {"tf32_cvt_rna_add", (void*)kern_tf32_cvt_rna_add_tput, (void*)kern_tf32_cvt_rna_add_lat, 80, 'f'},
    {"setp_selp_lt_s32", (void*)kern_setp_selp_lt_s32_tput, (void*)kern_setp_selp_lt_s32_lat, 75, 'i'},
    {"setp_selp_lt_f32", (void*)kern_setp_selp_lt_f32_tput, (void*)kern_setp_selp_lt_f32_lat, 75, 'f'},
    {"slct_s32", (void*)kern_slct_s32_tput, (void*)kern_slct_s32_lat, 75, 'i'},
    {"vadd2_u32", (void*)kern_vadd2_u32_tput, (void*)kern_vadd2_u32_lat, 75, 'u'},
    {"vsub2_u32", (void*)kern_vsub2_u32_tput, (void*)kern_vsub2_u32_lat, 75, 'u'},
    {"vadd4_u32", (void*)kern_vadd4_u32_tput, (void*)kern_vadd4_u32_lat, 75, 'u'},
    {"vsub4_u32", (void*)kern_vsub4_u32_tput, (void*)kern_vsub4_u32_lat, 75, 'u'},
    {"vabsdiff2_u32", (void*)kern_vabsdiff2_u32_tput, (void*)kern_vabsdiff2_u32_lat, 75, 'u'},
    {"vabsdiff4_u32", (void*)kern_vabsdiff4_u32_tput, (void*)kern_vabsdiff4_u32_lat, 75, 'u'},
    {"vmin_s32", (void*)kern_vmin_s32_tput, (void*)kern_vmin_s32_lat, 75, 'i'},
    {"vmax_s32", (void*)kern_vmax_s32_tput, (void*)kern_vmax_s32_lat, 75, 'i'},
};
const int n_tests = sizeof(tests)/sizeof(tests[0]);

int main(int argc, char** argv) {
    if (argc < 3) {
        fprintf(stderr, "Usage: %s <gpu_id> <n_iters> [n_warmup] [n_reps]\n", argv[0]);
        return 1;
    }

    int gpu_id = atoi(argv[1]);
    int n_iters = atoi(argv[2]);
    int n_warmup = argc > 3 ? atoi(argv[3]) : 10;
    int n_reps   = argc > 4 ? atoi(argv[4]) : 50;

    CHECK(cudaSetDevice(gpu_id));
    cudaDeviceProp prop;
    CHECK(cudaGetDeviceProperties(&prop, gpu_id));
    int l2_kb = prop.l2CacheSize / 1024;
    int gpu_sm = prop.major * 10 + prop.minor;

    printf("GPU,%s,sm_%d%d,%d,%d\n", prop.name,
           prop.major, prop.minor, prop.multiProcessorCount, l2_kb);
    fprintf(stderr, "GPU: %s (sm_%d), SMs: %d\n",
            prop.name, gpu_sm, prop.multiProcessorCount);
    fprintf(stderr, "n_iters=%d, n_warmup=%d, n_reps=%d, ops_per_iter=8\n",
            n_iters, n_warmup, n_reps);

    void* d_buf;
    CHECK(cudaMalloc(&d_buf, 128 * 8));

    for (int t = 0; t < n_tests; t++) {
        if (gpu_sm < tests[t].min_sm) {
            fprintf(stderr, "  %s: skipped (needs sm_%d, have sm_%d)\n",
                    tests[t].name, tests[t].min_sm, gpu_sm);
            continue;
        }
        fprintf(stderr, "  %s ...\n", tests[t].name);

        for (int mode = 0; mode < 2; mode++) {
            void* fn = mode == 0 ? tests[t].tput : tests[t].lat;
            const char* mode_str = mode == 0 ? "tput" : "lat";
            int divisor = n_iters * 8;

            float avg_ms = 0;
            switch (tests[t].out_type) {
                case 'f': avg_ms = bench_kernel<float>( fn, (float*)d_buf, n_iters, n_warmup, n_reps); break;
                case 'i': avg_ms = bench_kernel<int>(   fn, (int*)d_buf,   n_iters, n_warmup, n_reps); break;
                case 'u': avg_ms = bench_kernel<unsigned>(fn, (unsigned*)d_buf, n_iters, n_warmup, n_reps); break;
                case 's': avg_ms = bench_kernel<unsigned short>(fn, (unsigned short*)d_buf, n_iters, n_warmup, n_reps); break;
                case 'd': avg_ms = bench_kernel<double>(fn, (double*)d_buf, n_iters, n_warmup, n_reps); break;
            }

            double total_ns = avg_ms * 1e6;
            double ns_per_op = total_ns / divisor;
            double ops_per_ns = (total_ns > 0) ? divisor / total_ns : 0;
            printf("ARITH,%s,%s,%d,%.1f,%.3f,%.4f,%.1f\n",
                   tests[t].name, mode_str, n_iters, total_ns, ns_per_op,
                   ops_per_ns, avg_ms * n_reps);
        }
    }

    CHECK(cudaFree(d_buf));
    return 0;
}
